if (window.NOVA_KERNEL_VERSION === undefined) {
          const regionsWithAccessProblems = ['Warsaw', 'Kiev', 'Uzhgorod', 'Zaporozhye'];
          const URL_RU = 'https://sp1-nova.ru/api/core_version/';
          const URL_COM = 'https://sp1-nova.com/api/core_version/';
          const isKommo = APP.constant('current_brand_domain') === 'kommo';
          let isCom = isKommo;
          let status = 0;
          let xhr = null;

          if (Intl && !isCom) {
            const userTimeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
            const userRegion = userTimeZone?.split("/")?.at(-1);

            if (regionsWithAccessProblems.includes(userRegion)) {
              isCom = true;
              window.NOVA_SERVER = 'com';
            }
          }

          try {
            xhr = new XMLHttpRequest();

            setTimeout(() => {
              if (xhr.status !== 200 && !isCom) {
                xhr.abort();
                status = 0;
              }
            }, 2000);

            xhr.open('GET', isCom ? URL_COM : URL_RU, false);
            xhr.send();

            status = xhr.status;
          } catch {
            status = 0;
          }

          if (status === 200) {
            window.NOVA_KERNEL_VERSION = xhr.response;
            window.NOVA_SERVER = isCom ? 'com' : 'ru';
          } else {
            try {
              if (isCom) {
                isCom = false;

                xhr = new XMLHttpRequest();
                xhr.open('GET', URL_RU, false);
                xhr.send();

                status = xhr.status;
              } else {
                isCom = true;

                xhr = new XMLHttpRequest();
                xhr.open('GET', URL_COM, false);
                xhr.send();

                status = xhr.status;
              }
            } catch {
              console.error('nova/core_version')
            }
          }

          window.NOVA_KERNEL_VERSION = status === 200 ? xhr?.response : '.';
          window.NOVA_SERVER = isCom ? 'com' : 'ru';
        }
